mapper.select:
SELECT b.id, b.isbn, b.title, b.author, b.publisher, b.publish_date, b.cover_url, b.category_id, bc.category_name, b.description, b.total_stock, b.current_stock, b.status, b.create_time FROM book_info b LEFT JOIN book_category bc ON b.category_id = bc.id AND bc.is_deleted = 0 WHERE b.is_deleted = 0
AND (b.title LIKE CONCAT('%', #{keyword}, '%') OR b.author LIKE CONCAT('%', #{keyword}, '%') OR b.isbn LIKE CONCAT('%', #{keyword}, '%'))
AND (b.category_id = #{categoryId} OR b.category_id IN (SELECT id FROM book_category WHERE parent_id = #{categoryId} AND is_deleted = 0))
AND b.status = #{status}
ORDER BY b.create_time DESC LIMIT #{offset}, #{limit}
